import React from "react";
import "../styles/Footer.css";
import InstagramIcon from '@mui/icons-material/Instagram';
import FacebookIcon from '@mui/icons-material/Facebook';

function Footer(){
    return(
        <div className="Footer">
            <div>
                Social Networks 
                <InstagramIcon />
                <FacebookIcon />
            </div>
        </div>
    )
}
export default Footer;
